import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useCart } from '../../context/CartContext';
import orderService, { PaymentMethodType } from '../../services/orderService';

const paymentMethods: Array<{
    value: PaymentMethodType;
    label: string;
    badge: string;
    description: string;
}> = [
    {
        value: 'cod',
        label: 'Cash on Delivery',
        badge: 'COD',
        description: 'Pay the rider when your order arrives.',
    },
    {
        value: 'gcash',
        label: 'GCash',
        badge: 'GC',
        description: 'Use your GCash wallet for payment tracking.',
    },
    {
        value: 'card',
        label: 'Card',
        badge: 'CC',
        description: 'Charge the order to a debit or credit card.',
    },
    {
        value: 'bank_transfer',
        label: 'Bank Transfer',
        badge: 'BT',
        description: 'Complete payment using bank transfer instructions.',
    },
];

export default function DashboardCheckout() {
    const navigate = useNavigate();
    const { user } = useAuth();
    const { cartSummary, cartItems, clearCart, fetchCart } = useCart();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [slowHintVisible, setSlowHintVisible] = useState(false);
    const [showConfirmModal, setShowConfirmModal] = useState(false);

    const [paymentMethod, setPaymentMethod] = useState<PaymentMethodType>('cod');
    const defaultShippingAddress = (user?.shipping_address || user?.address || '').trim();
    const [shippingAddress, setShippingAddress] = useState(defaultShippingAddress);
    const [gcashForm, setGcashForm] = useState({
        accountName: '',
        mobileNumber: '',
        referenceNumber: '',
    });
    const [cardForm, setCardForm] = useState({
        cardholderName: '',
        cardNumber: '',
        expiry: '',
        cvv: '',
    });
    const [bankForm, setBankForm] = useState({
        accountName: '',
        bankName: '',
        referenceNumber: '',
    });

    const formatPeso = (value) => new Intl.NumberFormat('en-PH', {
        style: 'currency',
        currency: 'PHP',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(Number(value || 0));

    const summary = cartSummary || {
        subtotal: 0,
        shipping: 0,
        tax: 0,
        total: 0,
    };

    useEffect(() => {
        // Ensure checkout has fresh cart data when user lands directly on this page.
        if ((cartItems || []).length === 0) {
            fetchCart();
        }
    }, []);

    useEffect(() => {
        // Keep checkout prefilled from profile unless user already typed a value.
        if (!shippingAddress && defaultShippingAddress) {
            setShippingAddress(defaultShippingAddress);
        }
    }, [defaultShippingAddress, shippingAddress]);

    useEffect(() => {
        if (!loading) {
            setSlowHintVisible(false);
            return undefined;
        }

        const timer = window.setTimeout(() => {
            setSlowHintVisible(true);
        }, 1800);

        return () => window.clearTimeout(timer);
    }, [loading]);

    const handlePlaceOrder = () => {
        if ((cartItems || []).length === 0) {
            setError('Your cart is empty. Add items before checkout.');
            return;
        }

        if (!shippingAddress.trim()) {
            setError('Please enter a shipping address.');
            return;
        }

        const paymentError = getPaymentValidationError();
        if (paymentError) {
            setError(paymentError);
            return;
        }

        setShowConfirmModal(true);
    };

    const getPaymentValidationError = (): string | null => {
        if (paymentMethod === 'gcash') {
            if (!gcashForm.accountName.trim()) {
                return 'Please enter the GCash account name.';
            }

            const digits = gcashForm.mobileNumber.replace(/\D/g, '');
            if (digits.length < 10 || digits.length > 12) {
                return 'Please enter a valid GCash mobile number.';
            }
        }

        if (paymentMethod === 'card') {
            if (!cardForm.cardholderName.trim()) {
                return 'Please enter the cardholder name.';
            }

            const cardDigits = cardForm.cardNumber.replace(/\D/g, '');
            if (cardDigits.length < 13 || cardDigits.length > 19) {
                return 'Please enter a valid card number.';
            }

            if (!/^(0[1-9]|1[0-2])\/[0-9]{2}$/.test(cardForm.expiry.trim())) {
                return 'Please enter card expiry in MM/YY format.';
            }

            if (!/^[0-9]{3,4}$/.test(cardForm.cvv.trim())) {
                return 'Please enter a valid CVV.';
            }
        }

        if (paymentMethod === 'bank_transfer') {
            if (!bankForm.accountName.trim()) {
                return 'Please enter the bank account name.';
            }

            if (!bankForm.bankName.trim()) {
                return 'Please enter the bank name.';
            }

            if (!bankForm.referenceNumber.trim()) {
                return 'Please enter the bank transfer reference number.';
            }
        }

        return null;
    };

    const buildPaymentNotes = (): string | undefined => {
        if (paymentMethod === 'gcash') {
            return [
                'Payment Details',
                'Method: GCash',
                `GCash Name: ${gcashForm.accountName.trim()}`,
                `GCash Number: ${gcashForm.mobileNumber.trim()}`,
                gcashForm.referenceNumber.trim() ? `Reference: ${gcashForm.referenceNumber.trim()}` : '',
            ].filter(Boolean).join('\n');
        }

        if (paymentMethod === 'card') {
            const digits = cardForm.cardNumber.replace(/\D/g, '');
            const maskedCard = digits.length >= 4 ? `**** **** **** ${digits.slice(-4)}` : cardForm.cardNumber.trim();

            return [
                'Payment Details',
                'Method: Card',
                `Cardholder: ${cardForm.cardholderName.trim()}`,
                `Card: ${maskedCard}`,
                `Expiry: ${cardForm.expiry.trim()}`,
            ].filter(Boolean).join('\n');
        }

        if (paymentMethod === 'bank_transfer') {
            return [
                'Payment Details',
                'Method: Bank Transfer',
                `Account Name: ${bankForm.accountName.trim()}`,
                `Bank Name: ${bankForm.bankName.trim()}`,
                `Reference: ${bankForm.referenceNumber.trim()}`,
            ].filter(Boolean).join('\n');
        }

        return undefined;
    };

    const buildPaymentDetails = (): Record<string, string> | undefined => {
        if (paymentMethod === 'gcash') {
            return {
                method: 'gcash',
                account_name: gcashForm.accountName.trim(),
                mobile_number: gcashForm.mobileNumber.trim(),
                reference_number: gcashForm.referenceNumber.trim(),
            };
        }

        if (paymentMethod === 'card') {
            const digits = cardForm.cardNumber.replace(/\D/g, '');

            return {
                method: 'card',
                cardholder_name: cardForm.cardholderName.trim(),
                card_last4: digits.slice(-4),
                expiry: cardForm.expiry.trim(),
            };
        }

        if (paymentMethod === 'bank_transfer') {
            return {
                method: 'bank_transfer',
                account_name: bankForm.accountName.trim(),
                bank_name: bankForm.bankName.trim(),
                reference_number: bankForm.referenceNumber.trim(),
            };
        }

        return undefined;
    };

    const confirmPlaceOrder = async () => {
        setLoading(true);
        setError(null);

        try {
            const response = await orderService.createOrder({
                payment_method: paymentMethod,
                shipping_address: shippingAddress.trim(),
                notes: buildPaymentNotes(),
                payment_details: buildPaymentDetails(),
                items: cartItems.map((item) => ({
                    product_id: item.product_id || item.product?.id,
                    quantity: item.quantity,
                })),
            });
            const createdOrder = response?.data?.data || response?.data;
            setShowConfirmModal(false);
            await clearCart();
            navigate(`/dashboard/checkout-success`, {
                state: { order: createdOrder },
            });
        } catch (err) {
            const data = err?.response?.data || {};
            const rawDetail = data?.error?.message || data?.error?.details || data?.details || '';
            const detail = typeof rawDetail === 'string' ? rawDetail.trim() : '';
            const message = data?.message || 'Failed to create order';
            setError(detail ? `${message} (${detail})` : message);
        } finally {
            setLoading(false);
        }
    };

    const selectedPayment = paymentMethods.find((item) => item.value === paymentMethod) || paymentMethods[0];

    return (
        <section className="checkout-page-shell">
            <h1 className="checkout-page-title">Checkout</h1>

            {error && <div className="alert alert-danger">{error}</div>}
            {loading && slowHintVisible && (
                <div className="alert alert-info" role="status">
                    Confirming your order. Network is slow, please wait a moment...
                </div>
            )}

            <div className="dashboard-grid dashboard-grid--checkout">
                <div className="checkout-main-column">
                    <section className="dashboard-panel checkout-panel checkout-delivery-card">
                        <h2>Delivery Address</h2>

                        <div className="checkout-field-group">
                            <label>Name</label>
                            <input type="text" value={user?.name || ''} readOnly className="checkout-readonly-input" />
                        </div>

                        <div className="checkout-field-group">
                            <label>Email</label>
                            <input type="text" value={user?.email || ''} readOnly className="checkout-readonly-input" />
                        </div>

                        <div className="checkout-field-group">
                            <label>Phone</label>
                            <input type="text" value={user?.phone || ''} readOnly className="checkout-readonly-input" />
                        </div>

                        <div className="checkout-field-group">
                            <label>Address</label>
                            <textarea
                                value={shippingAddress}
                                onChange={(event) => setShippingAddress(event.target.value)}
                                rows={3}
                                className="checkout-readonly-input"
                                placeholder="Enter your shipping address"
                            />
                        </div>

                        <button
                            type="button"
                            className="btn btn-outline-primary"
                            onClick={() => setShippingAddress(defaultShippingAddress)}
                        >
                            Use Profile Address
                        </button>
                    </section>

                    <section className="dashboard-panel checkout-panel">
                        <h2>Items in Your Order</h2>
                        {cartItems.length === 0 ? (
                            <p className="muted">Your cart is empty.</p>
                        ) : (
                            <div className="dashboard-order-list" style={{ marginBottom: '0.9rem' }}>
                                {cartItems.map((item) => (
                                    <article key={item.id} className="dashboard-order-item">
                                        <div>
                                            <strong>{item.product?.name || 'Item'}</strong>
                                            <p>{item.product?.brand || 'CarVex'}</p>
                                        </div>
                                        <div style={{ textAlign: 'right' }}>
                                            <p style={{ margin: 0 }}>Qty: {item.quantity}</p>
                                            <strong>{formatPeso(Number(item.product?.price || 0) * Number(item.quantity || 0))}</strong>
                                        </div>
                                    </article>
                                ))}
                            </div>
                        )}
                    </section>

                    <section className="dashboard-panel checkout-panel">
                        <h2>Payment Method</h2>
                        <div className="payment-method-grid" role="radiogroup" aria-label="Payment method">
                            {paymentMethods.map((method) => (
                                <label
                                    key={method.value}
                                    className={`payment-method-card ${paymentMethod === method.value ? 'is-selected' : ''}`}
                                    onClick={() => setPaymentMethod(method.value)}
                                >
                                    <input
                                        type="radio"
                                        name="payment_method"
                                        value={method.value}
                                        checked={paymentMethod === method.value}
                                        onChange={() => setPaymentMethod(method.value)}
                                        className="payment-method-card__radio"
                                    />
                                    <span className="payment-method-card__badge">{method.badge}</span>
                                    <strong>{method.label}</strong>
                                    <p>{method.description}</p>
                                </label>
                            ))}
                        </div>

                        {paymentMethod === 'gcash' && (
                            <div className="checkout-payment-form">
                                <p className="checkout-payment-form__hint">Fill in your GCash details for payment tracking.</p>
                                <div className="checkout-method-fields">
                                    <div className="checkout-field-group">
                                        <label>GCash Account Name</label>
                                        <input
                                            type="text"
                                            value={gcashForm.accountName}
                                            onChange={(event) => setGcashForm((prev) => ({ ...prev, accountName: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="Juan Dela Cruz"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>GCash Mobile Number</label>
                                        <input
                                            type="text"
                                            value={gcashForm.mobileNumber}
                                            onChange={(event) => setGcashForm((prev) => ({ ...prev, mobileNumber: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="09XXXXXXXXX"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>Reference Number (Optional)</label>
                                        <input
                                            type="text"
                                            value={gcashForm.referenceNumber}
                                            onChange={(event) => setGcashForm((prev) => ({ ...prev, referenceNumber: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="e.g. GCSH12345"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        {paymentMethod === 'card' && (
                            <div className="checkout-payment-form">
                                <p className="checkout-payment-form__hint">Enter your card details to continue checkout.</p>
                                <div className="checkout-method-fields checkout-method-fields--two-col">
                                    <div className="checkout-field-group">
                                        <label>Cardholder Name</label>
                                        <input
                                            type="text"
                                            value={cardForm.cardholderName}
                                            onChange={(event) => setCardForm((prev) => ({ ...prev, cardholderName: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="Name on card"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>Card Number</label>
                                        <input
                                            type="text"
                                            value={cardForm.cardNumber}
                                            onChange={(event) => setCardForm((prev) => ({ ...prev, cardNumber: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="1234 5678 9012 3456"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>Expiry (MM/YY)</label>
                                        <input
                                            type="text"
                                            value={cardForm.expiry}
                                            onChange={(event) => setCardForm((prev) => ({ ...prev, expiry: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="MM/YY"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>CVV</label>
                                        <input
                                            type="password"
                                            value={cardForm.cvv}
                                            onChange={(event) => setCardForm((prev) => ({ ...prev, cvv: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="***"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        {paymentMethod === 'bank_transfer' && (
                            <div className="checkout-payment-form">
                                <p className="checkout-payment-form__hint">Provide transfer details so we can verify your payment faster.</p>
                                <div className="checkout-method-fields">
                                    <div className="checkout-field-group">
                                        <label>Account Name</label>
                                        <input
                                            type="text"
                                            value={bankForm.accountName}
                                            onChange={(event) => setBankForm((prev) => ({ ...prev, accountName: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="Name used in transfer"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>Bank Name</label>
                                        <input
                                            type="text"
                                            value={bankForm.bankName}
                                            onChange={(event) => setBankForm((prev) => ({ ...prev, bankName: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="Bank of the transfer"
                                        />
                                    </div>
                                    <div className="checkout-field-group">
                                        <label>Reference Number</label>
                                        <input
                                            type="text"
                                            value={bankForm.referenceNumber}
                                            onChange={(event) => setBankForm((prev) => ({ ...prev, referenceNumber: event.target.value }))}
                                            className="checkout-readonly-input"
                                            placeholder="Transfer reference"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}
                    </section>
                </div>

                <aside className="dashboard-panel checkout-summary-panel">
                    <h2>Order Summary</h2>

                    <div className="summary-item">
                        <span>Subtotal</span>
                        <strong>{formatPeso(summary.subtotal)}</strong>
                    </div>

                    <div className="summary-item">
                        <span>Shipping</span>
                        <strong>{formatPeso(summary.shipping)}</strong>
                    </div>

                    <div className="summary-item">
                        <span>Tax (10%)</span>
                        <strong>{formatPeso(summary.tax)}</strong>
                    </div>

                    <div className="summary-item summary-item--total">
                        <span>Total</span>
                        <strong>{formatPeso(summary.total)}</strong>
                    </div>

                    <div className="payment-note">
                        <p>Payment Method:</p>
                        <strong>{selectedPayment.label}</strong>
                    </div>

                    <button
                        type="button"
                        className="btn btn-primary btn-lg btn-block checkout-place-order-btn"
                        onClick={handlePlaceOrder}
                        disabled={loading || (cartItems || []).length === 0}
                    >
                        {loading ? 'Processing...' : 'Place Order'}
                    </button>

                    <p className="checkout-summary-terms">By placing your order, you agree to our terms and conditions</p>
                </aside>
            </div>

            {showConfirmModal && (
                <div className="checkout-confirm-modal" role="dialog" aria-modal="true">
                    <div className="checkout-confirm-modal__backdrop" onClick={() => !loading && setShowConfirmModal(false)} />
                    <div className="checkout-confirm-modal__panel">
                        <div className="checkout-confirm-modal__head">
                            <h2>Confirm your order</h2>
                            <button
                                type="button"
                                className="checkout-confirm-modal__close"
                                aria-label="Close confirmation"
                                onClick={() => !loading && setShowConfirmModal(false)}
                                disabled={loading}
                            >
                                ×
                            </button>
                        </div>

                        <p className="checkout-confirm-modal__subtitle">
                            Please review your details before completing the purchase.
                        </p>

                        <div className="checkout-confirm-modal__body">
                            <div className="confirm-item">
                                <span>Payment Method:</span>
                                <strong>{selectedPayment.label}</strong>
                            </div>
                            <div className="confirm-item">
                                <span>Total Amount:</span>
                                <strong>{formatPeso(summary.total)}</strong>
                            </div>
                        </div>

                        <div className="checkout-confirm-modal__actions">
                            <button
                                type="button"
                                className="btn btn-outline-primary"
                                onClick={() => setShowConfirmModal(false)}
                                disabled={loading}
                            >
                                Cancel
                            </button>
                            <button
                                type="button"
                                className="btn btn-primary"
                                onClick={confirmPlaceOrder}
                                disabled={loading}
                            >
                                {loading ? 'Processing...' : 'Confirm Order'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </section>
    );
}
